#!/bin/bash\n\n# ╔═══════════════════════════════════════════════════════════╗\n# ║          🤖 MANOS APK Auto Builder - Linux/Mac             ║\n# ║                                                            ║\n# ║         صُنعت في العراق العظيم 🇮🇶                        ║\n# ║      على يد: أمير الحشداوي (fhd3dail-pixel)              ║\n# ╚═══════════════════════════════════════════════════════════╝\n\nset -e\n\necho \"\"\necho \"╔════════════════════════════════════════════════════════════╗\"\necho \"║         🚀 MANOS APK Builder - Linux/Mac Edition          ║\"\necho \"║                                                            ║\"\necho \"║      صُنعت في العراق العظيم 🇮🇶                           ║\"\necho \"║   على يد: أمير الحشداوي (fhd3dail-pixel)                 ║\"\necho \"║                                                            ║\"\necho \"║  جاري بناء التطبيق تلقائياً...                            ║\"\necho \"╚════════════════════════════════════════════════════════════╝\"\necho \"\"\n\n# فحص المتطلبات\necho \"✓ فحص المتطلبات...\"\n\nif ! command -v java &> /dev/null; then\n    echo \"❌ Java غير مثبت!\"\n    echo \"📥 حمّل من: https://www.oracle.com/java/technologies/downloads/\"\n    exit 1\nfi\necho \"✅ Java موجود\"\n\nif ! command -v gradle &> /dev/null && [ ! -f \"frontend/gradlew\" ]; then\n    echo \"❌ Gradle غير مثبت!\"\n    exit 1\nfi\necho \"✅ Gradle موجود\"\n\n# الانتقال لمجلد frontend\necho \"\"\necho \"✓ الانتقال لمجلد frontend...\"\ncd frontend\necho \"✅ تم الانتقال\"\n\n# إعطاء صلاحيات gradlew\necho \"\"\necho \"✓ إعطاء الصلاحيات...\"\nchmod +x gradlew\necho \"✅ تم\"\n\n# بناء APK\necho \"\"\necho \"✓ جاري بناء APK... (هذا قد يستغرق 3-5 دقائق)\"\necho \"\"\n./gradlew assembleDebug\n\nif [ $? -ne 0 ]; then\n    echo \"\"\n    echo \"❌ خطأ في البناء!\"\n    exit 1\nfi\n\necho \"\"\necho \"✅ تم البناء بنجاح!\"\necho \"\"\necho \"╔════════════════════════════════════════════════════════════╗\"\necho \"║              🎉 تم إنشاء APK بنجاح!                       ║\"\necho \"╚════════════════════════════════════════════════════════════╝\"\necho \"\"\necho \"📱 موقع الملف:\"\necho \"   $(pwd)/app/build/outputs/apk/debug/app-debug.apk\"\necho \"\"\necho \"📝 الخطوات التالية:\"\necho \"   1. انسخ الملف من المجلد أعلاه\"\necho \"   2. انقله إلى جهازك الذكي\"\necho \"   3. فعّل 'تثبيت من مصادر غير معروفة'\"\necho \"   4. ثبّت التطبيق\"\necho \"   5. استمتع!\"\necho \"\"\necho \"🔗 رابط المستودع:\"\necho \"   https://github.com/fhd3dail-pixel/MANOS\"\necho \"\"\necho \"✨ صُنعت في العراق العظيم 🇮🇶\"\necho \"✨ على يد: أمير الحشداوي\"\necho \"\"\n"